"/* Tree Lines using CSS Pseudo-elements */
.mindmap-children {
  display: flex;
  flex-direction: column;
  margin-left: 40px; 
  position: relative;
  padding-left: 0;
}

.mindmap-child-wrapper {
  position: relative;
  display: flex;
  padding: 4px 0;
}

/* Vertical line container */
.mindmap-children::before {
  content: '';
  position: absolute;
  top: 50%; /* We will adjust this via a trick or keep it simple */
  left: -20px;
  width: 20px;
}

/* We can use the classic CSS tree structure */
.mindmap-child-wrapper::before, .mindmap-child-wrapper::after {
  content: '';
  position: absolute;
  left: -20px;
}

/* Horizontal line to the item */
.mindmap-child-wrapper::before {
  border-top: 2px solid #818cf8;
  top: 50%;
  width: 20px;
  height: 0;
}

/* Vertical line for the left column */
.mindmap-child-wrapper::after {
  border-left: 2px solid #818cf8;
  height: 100%;
  width: 0px;
  top: 0;
}

/* First child - vertical line goes down from middle */
.mindmap-child-wrapper:first-child::after {
  top: 50%;
  height: 50%;
  border-top-left-radius: 8px; /* Curve! */
}

/* Last child - vertical line goes up to middle */
.mindmap-child-wrapper:last-child::after {
  height: 50%;
  bottom: 50%;
  top: auto;
  border-bottom-left-radius: 8px; /* Curve! */
}

/* If only one child, no vertical line, just horizontal */
.mindmap-child-wrapper:first-child:last-child::after {
  display: none;
}
"

