"/* Tree Lines using CSS Pseudo-elements */
.mindmap-children {
  display: flex;
  flex-direction: column;
  margin-left: 50px; 
  position: relative;
  padding-left: 0;
}

.mindmap-child-wrapper {
  position: relative;
  display: flex;
  padding: 8px 0;
}

/* We can use the classic CSS tree structure */
.mindmap-child-wrapper::before, .mindmap-child-wrapper::after {
  content: '';
  position: absolute;
  left: -25px;
}

/* Horizontal line to the item */
.mindmap-child-wrapper::before {
  border-top: 3px solid #818cf8;
  top: 50%;
  width: 25px;
  height: 0;
}

/* Vertical line for the left column */
.mindmap-child-wrapper::after {
  border-left: 3px solid #818cf8;
  height: 100%;
  width: 0px;
  top: 0;
}

/* First child - vertical line goes down from middle */
.mindmap-child-wrapper:first-child::after {
  top: 50%;
  height: 50%;
  border-top-left-radius: 24px; /* Big Curve! */
}

/* Last child - vertical line goes up to middle */
.mindmap-child-wrapper:last-child::after {
  height: 50%;
  bottom: 50%;
  top: auto;
  border-bottom-left-radius: 24px; /* Big Curve! */
}

/* If only one child, no vertical line, just horizontal */
.mindmap-child-wrapper:first-child:last-child::after {
  display: none;
}

/* Connecting line from parent to the vertical spine */
.mindmap-children::before {
  content: '';
  position: absolute;
  top: 50%;
  left: -50px;
  width: 25px;
  border-top: 3px solid #818cf8;
}

/* Pop up animation for newly opened nodes */
@keyframes popUp {
  0% { transform: scale(0.8); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

.mindmap-children > .mindmap-child-wrapper {
  animation: popUp 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
}"

